var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드, 혼자 너무 앞서가면 안 돼. 어둠 속에 뭐가 있을지 몰라.","JPN":"シェパード、あまり一人で先に行っちゃ駄目だ。暗闇の中には何があるかわからないから。","ENG":"Shepherd, don't go too far out alone. There might be something in the dark.","TWN":"牧羊犬，別太往前。你永遠不知道黑暗中會有什麼。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"괜찮아요. 어두워도 잘 보여요.","JPN":"大丈夫。暗くてもちゃんと見えるよ。","ENG":"It's okay. Shepherd can see well in the dark.","TWN":"沒關係。牧羊犬在黑暗中也能看得見。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그리고 더 빨리 가야…","JPN":"それに、もっと早く行かないと……","ENG":"And we have to hurry–","TWN":"還能走得更快……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…앗.","JPN":"……あっ。","ENG":"...Ouch.","TWN":"……啊。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"조심해. 앞을 보고 가야지.","JPN":"気をつけて。前を向いて行かないと。","ENG":"Be careful. Look ahead as you go.","TWN":"小心點啊……走路看著前面。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"괜찮니? 세게 부딪히는 소리가 났는데.","JPN":"大丈夫？　強くぶつけた音がしたけど。","ENG":"Are you okay? It sounded like you bumped into it pretty hard.","TWN":"沒事吧？剛剛好大一聲。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…응. 셰퍼드 튼튼해서 괜찮아요.","JPN":"……うん。シェパードは頑丈だから、平気。","ENG":"...Yeah. It's okay. Because Shepherd is strong.","TWN":"……牧羊犬很強壯的，沒關係。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이런 길 한복판에 나무가 자라 있다니… 정말 별일이네.","JPN":"こんな道の真ん中に木が生えてるなんて……本当に珍しい。","ENG":"I can't believe there's a tree just growing in the middle of the path like that... How strange.","TWN":"路中間竟然會有一棵這樣的樹……真不尋常。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드가 다니는 길 주변엔 식물 자라요.","JPN":"シェパードが通る道の周りには、植物が生えるの。","ENG":"Wherever Shepherd goes, plants grow nearby.","TWN":"牧羊犬走過的路都會長上植物。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"바닥에도 벽에도 자라서 어른들이 불편하다고 했어요.","JPN":"床にも壁にも生えてきて、大人たちが面倒だって言ってた。","ENG":"But the adults said that it was an inconvenience because they grew on the floors and walls.","TWN":"大人們說這樣很不方便，因為地板上和牆上也都是植物。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"식물이 자라는 게… 네가 있어서 그런 거라고?","JPN":"あなたがいるから……植物が生える？","ENG":"The plants are growing... because of you?","TWN":"長出植物……是因為你嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응, 셰퍼드가 집에 오래 머무르면 식물도 더 많이 자라요.","JPN":"うん、シェパードが長居すれば、植物ももっとたくさん生えてくるの。","ENG":"Uh-huh. If Shepherd stays at home for long, plants grow even more.","TWN":"嗯，牧羊犬待在家裡的時間越長，植物就會長得越多。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"하늘도 햇볕도 없지만, 봄에는 더 무럭무럭 자라고요.","JPN":"空も日光もないけど、春にはもっともっと生えるよ。","ENG":"Even though there is no sky and sunlight, they grow faster in spring.","TWN":"即使沒有天空和陽光。而且春天會長得更加旺盛。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"게다가, 계절마다 자라나는 식물도 다르거든요.","JPN":"それに、季節によって生える植物も違うんだ。","ENG":"Also, different plants grow depending on the season.","TWN":"每個季節，生長的植物也不同。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"계절이라니. 이면세계에 그런 게 존재할 리가…","JPN":"季節って。裏世界にそんなもの存在するわけ……","ENG":"Season? But those don't exist in the Counterside...","TWN":"季節？在異界怎麼可能存在這些……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…찾았다.","JPN":"……見つけた。","ENG":"…Found it.","TWN":"……找到了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"이거 먹어요. 어른들도 좋아했어요.","JPN":"これ食べて。大人たちも好きだった。","ENG":"Eat this. Adults like it.","TWN":"請吃吧。大人們都喜歡這個的。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이건 포도잖아? 아니, 머루인가…?","JPN":"これは、ブドウ？　いや、ヤマブドウか……？","ENG":"This is a grape? No, is it a wild grape...?","TWN":"這些是葡萄嗎？不對，是山葡萄嗎……？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"이름은 몰라요. 여름 끝무렵에 여기서 자라요.","JPN":"名前は知らない。夏の終わりにここから生えるの。","ENG":"Shepherd doesn't know the name. But they grow at the end of summer.","TWN":"牧羊犬不知道它的名字。但是夏天快結束的時候它就會長出來。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"관심 안 주면 금방 시들어서 자주 와서 보살폈어요.","JPN":"世話しないとすぐ枯れちゃうから、よく見てたんだ。","ENG":"They also wither away if unattended, so Shepherd came here often to take care of them.","TWN":"一不注意很快就會枯萎了，所以牧羊犬經常過來照顧它。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"네가 열매를 맺게 했다고?","JPN":"あなたが実らせた？","ENG":"You helped it bear fruit?","TWN":"你讓它結出了果實？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응.","JPN":"うん。","ENG":"Uh-huh.","TWN":"嗯、嗯。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"배고프면 마음 모양이 길쭉해져요. 당신처럼.","JPN":"お腹空いたら心の形が細長くなるの。あなたのように。","ENG":"People's heart shapes become long when they're hungry. Just like yours.","TWN":"人類肚子餓的時候，心的形狀就會變長。就像現在的史賓瑟一樣。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처는 항상 배가 고팠는데, 그래서 항상 화가 난 걸지도 몰라요.","JPN":"ラッチャーはいつもお腹を空かせてたけど、それでいつも怒ってたのかもしれないよ。","ENG":"Lurcher is always hungry. Maybe that's why he's always violent.","TWN":"而獵犬總是很餓，這可能就是它總是發火的原因。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"난폭해지기 전에 얼른 먹어요. 얼른.","JPN":"乱暴になるまえに、早く食べて。早く。","ENG":"You should eat before you get violent. Hurry.","TWN":"在變得暴力之前請快點吃掉吧。快點快點。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그, 그러니…?","JPN":"そ、そう……？","ENG":"I-is that so...?","TWN":"是、是嗎……？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"저렇게 눈을 반짝이는 건 처음 보네.","JPN":"あんなに目がキラキラしてるのは初めて見た。","ENG":"I've never seen her eyes twinkle like that before.","TWN":"第一次看到她的眼睛那麼亮。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};